previewCss:
.darma-loader-darma-custom-248 {
  color: var(--loader-color, #16a34a);
  display: inline-grid;
}
.darma-loader-darma-custom-248:before,
.darma-loader-darma-custom-248:after {
  content: "";
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  clip-path: inset(0 100% 0 0);
  animation: darma-loader-darma-custom-248-l9 1s infinite linear;
}
.darma-loader-darma-custom-248:after {
  scale: -1 1;
}
@keyframes darma-loader-darma-custom-248-l9{
  90%,to {clip-path: inset(0)}
}

